// 简化版 axios 实现
(function(window) {
  'use strict';

  function createXHR() {
    if (window.XMLHttpRequest) {
      return new XMLHttpRequest();
    }
    throw new Error('XMLHttpRequest not supported');
  }

  function buildURL(url, params) {
    if (!params) return url;
    
    var queryString = [];
    for (var key in params) {
      if (params.hasOwnProperty(key)) {
        var value = params[key];
        if (value !== null && value !== undefined) {
          queryString.push(encodeURIComponent(key) + '=' + encodeURIComponent(value));
        }
      }
    }
    
    if (queryString.length > 0) {
      url += (url.indexOf('?') === -1 ? '?' : '&') + queryString.join('&');
    }
    
    return url;
  }

  function axios(config) {
    return new Promise(function(resolve, reject) {
      var method = config.method || 'get';
      var url = buildURL(config.url, config.params);
      var data = config.data;
      var headers = Object.assign({}, axios.defaults.headers.common, config.headers || {});
      
      var xhr = createXHR();
      xhr.open(method.toUpperCase(), url, true);
      
      xhr.setRequestHeader('Accept', 'application/json, text/plain, */*');
      
      if (method.toLowerCase() === 'post' || method.toLowerCase() === 'put' || method.toLowerCase() === 'patch') {
        xhr.setRequestHeader('Content-Type', 'application/json;charset=utf-8');
      }
      
      for (var key in headers) {
        if (headers.hasOwnProperty(key)) {
          xhr.setRequestHeader(key, headers[key]);
        }
      }
      
      xhr.onload = function() {
        var responseData = xhr.responseText;
        try {
          responseData = JSON.parse(responseData);
        } catch (e) {}
        
        var response = {
          data: responseData,
          status: xhr.status,
          statusText: xhr.statusText,
          headers: xhr.getAllResponseHeaders(),
          config: config
        };
        
        if (xhr.status >= 200 && xhr.status < 300) {
          resolve(response);
        } else {
          reject(response);
        }
      };
      
      xhr.onerror = function() {
        reject(new Error('Network Error'));
      };
      
      var sendData = data ? JSON.stringify(data) : null;
      xhr.send(sendData);
    });
  }

  axios.defaults = { headers: { common: {} } };

  axios.get = function(url, config) {
    return axios(Object.assign({}, config || {}, { method: 'get', url: url }));
  };

  axios.post = function(url, data, config) {
    return axios(Object.assign({}, config || {}, { method: 'post', url: url, data: data }));
  };

  axios.put = function(url, data, config) {
    return axios(Object.assign({}, config || {}, { method: 'put', url: url, data: data }));
  };

  axios.delete = function(url, config) {
    return axios(Object.assign({}, config || {}, { method: 'delete', url: url }));
  };

  axios.patch = function(url, data, config) {
    return axios(Object.assign({}, config || {}, { method: 'patch', url: url, data: data }));
  };

  axios.head = function(url, config) {
    return axios(Object.assign({}, config || {}, { method: 'head', url: url }));
  };

  axios.options = function(url, config) {
    return axios(Object.assign({}, config || {}, { method: 'options', url: url }));
  };

  window.axios = axios;
})(window);
